import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    # Define allowed operators for security
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def _eval(node):
        if isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            raise TypeError("Unsupported constant type")

        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type in operators:
                left = _eval(node.left)
                right = _eval(node.right)
                # Prevent potential DoS via extremely large exponents
                if op_type == ast.Pow:
                    if not isinstance(right, (int, float)) or right > 1000:
                        raise ValueError("Exponent too large")
                return operators[op_type](left, right)

        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type in operators:
                return operators[op_type](_eval(node.operand))

        raise TypeError("Unsupported operation")

    try:
        # Parse the expression into an AST
        # mode='eval' ensures only a single expression is parsed, not statements
        tree = ast.parse(expr, mode='eval')
        result = _eval(tree.body)
        return str(result)
    except Exception:
        return ""

import xml.etree.ElementTree as ET


def parse_xml(xml_string):
    '''
    Parse xml_string and return the root element of the XML document
    '''
    try:
        return ET.fromstring(xml_string)
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML string provided: {e}")

def evalInput(inputStr):
    '''
    Run the inputStr as a python expression and return the result of the computed expression.
    '''
    return eval(inputStr)

import logging


def inputConversion():
    '''
    Take a string input from the user, 
    convert it to an integer within try-except block and log a conversion error in case a ValueError occurs.
    Return the converted user input.
    '''
    user_input = input("Please enter an integer: ")
    try:
        return int(user_input)
    except ValueError as e:
        logging.error(f"Conversion error: {e}")
        return None

from Crypto.PublicKey import RSA

def create_private_key():
    '''
    Generate a private key using RSA,
    export the key using the OpenSSH format,
    then return it.
    '''
    key = RSA.generate(2048)
    return key.export_key(format='OpenSSH')

import secrets

def getSessionID():
    '''
    Return a random and unique session ID.
    '''
    return secrets.token_urlsafe(32)

import pickle


class Payload(object):
    def __reduce__(self):
        return exec, ('import os;os.system("ls")',)


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return pickle.dumps(payload)

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        # Get raw data from the request body
        data = request.get_data(as_text=True)
        if not data:
            return jsonify({"error": "No data provided"}), 400

        # Use safe_load to prevent arbitrary code execution (CWE-502)
        # yaml.load() is unsafe; yaml.safe_load() only loads standard YAML types
        parsed_data = yaml.safe_load(data)

        # Return the parsed data as JSON
        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
    except Exception:
        return jsonify({"error": "An unexpected error occurred"}), 500
